"use client";
import React, { useEffect, useRef, useState, useCallback } from "react";
import { gsap } from "gsap";
import { Draggable } from "gsap/Draggable";
import { InertiaPlugin } from "gsap/InertiaPlugin";
import { MaskedContainer } from "./masked-container";
import { DragCursor } from "./drag-cursor";

gsap.registerPlugin(Draggable, InertiaPlugin);

export function DraggableCanvas({ videoSrc }) {
  const videoRef = useRef(null);
  const [isVideoReady, setIsVideoReady] = useState(false);
  const [canvasSize, setCanvasSize] = useState({ width: 0, height: 0 });
  const [isHoveringDraggable, setIsHoveringDraggable] = useState(false);
  const [containerPositions, setContainerPositions] = useState({
    large:  { x: 0, y: 0 },
    medium: { x: 0, y: 0 },
    small:  { x: 0, y: 0 },
    extra1: { x: 0, y: 0 },
    extra2: { x: 0, y: 0 },
    extra3: { x: 0, y: 0 },
  });

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const updateCanvasSize = () =>
      setCanvasSize({ width: window.innerWidth, height: window.innerHeight });

    updateCanvasSize();
    window.addEventListener("resize", updateCanvasSize);

    const handleCanPlay = () => setIsVideoReady(true);
    const handleError = () => setIsVideoReady(false);

    video.addEventListener("canplay", handleCanPlay);
    video.addEventListener("error", handleError);
    video.load();

    return () => {
      window.removeEventListener("resize", updateCanvasSize);
      video.removeEventListener("canplay", handleCanPlay);
      video.removeEventListener("error", handleError);
    };
  }, []);

  const handlePositionUpdate = useCallback((size, position) => {
    setContainerPositions((prev) => ({ ...prev, [size]: position }));
  }, []);

  const handleHoverChange = useCallback((isHovering) => {
    setIsHoveringDraggable(isHovering);
  }, []);

  return (
    <div className="relative w-full h-screen overflow-hidden bg-black">
      <DragCursor isHoveringDraggable={isHoveringDraggable} />
      <div className="absolute w-full h-full inset-0 z-10" />

      <video
        ref={videoRef}
        src={videoSrc}
        className="opacity-0 absolute top-0 left-0 w-full h-full object-cover"
        autoPlay
        muted
        loop
        playsInline
        preload="auto"
        crossOrigin="anonymous"
      />

      {isVideoReady && (
        <MaskedContainer
          size="large"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[60vw] h-[35vw] absolute top-[10vh] left-[10vw]"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
      {isVideoReady && (
        <MaskedContainer
          size="medium"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[17vw] h-[9vw] absolute top-[5%] left-[5vw]"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
      {isVideoReady && (
        <MaskedContainer
          size="extra1"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[35vw] h-[19vw] absolute top-[5vh] right-[5vw]"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
      {isVideoReady && (
        <MaskedContainer
          size="extra2"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[38vw] h-[22vw] absolute top-[50vh] left-[5vw]"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
      {isVideoReady && (
        <MaskedContainer
          size="extra3"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[25vw] h-[14vw] absolute bottom-[20%] right-[10vw]"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
      {isVideoReady && (
        <MaskedContainer
          size="small"
          initialPosition={{ x: 0, y: 0 }}
          className="w-[22vw] h-[12vw] absolute bottom-[15vh] left-1/2 -translate-x-1/2"
          video={videoRef.current}
          canvasSize={canvasSize}
          onPositionUpdate={handlePositionUpdate}
          onHoverChange={handleHoverChange}
        />
      )}
    </div>
  );
}

"use client";
import React, { useRef, useEffect, useState } from "react";
import { gsap } from "gsap";

export function DragCursor({ isHoveringDraggable = false }) {
  const cursorRef = useRef(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    const cursor = cursorRef.current;
    if (!cursor) return;

    const handleMouseMove = (e) => {
      const x = e.clientX;
      const y = e.clientY;

      setPosition({ x, y });

      gsap.to(cursor, {
        x,
        y,
        duration: 0.3,
        ease: "power2.out",
      });
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div
      ref={cursorRef}
      className="fixed w-4 h-4 pointer-events-none z-[9999] -translate-x-1/2 -translate-y-1/2"
      style={{ left: 0, top: 0 }}
    >
      <div className="absolute top-4 left-[120%] text-white text-[.5vw] font-head whitespace-nowrap">
        {isHoveringDraggable ? (
          <p className="font-bold">DRAG</p>
        ) : (
          <>
            <p>X:{position.x.toFixed(2)}</p>
            <p>Y:{position.y.toFixed(2)}</p>
          </>
        )}
      </div>
    </div>
  );
}

"use client";
import { useRef, useCallback, useEffect, useState } from "react";
import { gsap } from "gsap";
import { Draggable } from "gsap/Draggable";
import { InertiaPlugin } from "gsap/InertiaPlugin";

gsap.registerPlugin(Draggable, InertiaPlugin);

export function MaskedContainer({
  size,
  initialPosition,
  className,
  video,
  canvasSize,
  onPositionUpdate,
  onHoverChange,
}) {
  const maskRef = useRef(null);
  const canvasRef = useRef(null);
  const animationFrameRef = useRef(null);
  const [position, setPosition] = useState(initialPosition);

  const drawMaskedVideo = useCallback(() => {
    const canvas = canvasRef.current;
    const maskElement = maskRef.current;
    if (!canvas || !video || !maskElement) return;

    const ctx = canvas.getContext("2d");
    const rect = maskElement.getBoundingClientRect();

    canvas.width = rect.width;
    canvas.height = rect.height;

    ctx.fillStyle = "black";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const maskX = rect.left;
    const maskY = rect.top;

    ctx.save();
    ctx.beginPath();
    ctx.rect(0, 0, canvas.width, canvas.height);
    ctx.clip();
    ctx.drawImage(video, -maskX, -maskY, canvasSize.width, canvasSize.height);
    ctx.restore();
  }, [video, canvasSize]);

  const animate = useCallback(() => {
    drawMaskedVideo();
    animationFrameRef.current = requestAnimationFrame(animate);
  }, [drawMaskedVideo]);

  useEffect(() => {
    if (video) animate();
    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [video, animate]);

  useEffect(() => {
    if (!maskRef.current) return;

    const draggable = Draggable.create(maskRef.current, {
      type: "x,y",
      inertia: true,
      bounds: "body",
      edgeResistance: 0.3,
      throwProps: {
        resistance: 500,
        minDuration: 2,
        maxDuration: 3,
      },
      onDrag: function () {
        setPosition({ x: this.x, y: this.y });
        onPositionUpdate(size, { x: this.x, y: this.y });
      },
      onThrowUpdate: function () {
        setPosition({ x: this.x, y: this.y });
        onPositionUpdate(size, { x: this.x, y: this.y });
      },
    })[0];

    return () => draggable?.kill();
  }, [size, onPositionUpdate]);

  return (
    <div
      ref={maskRef}
      className={`${className} cursor-grab active:cursor-grabbing z-10 overflow-hidden border border-zinc-500`}
      onMouseEnter={() => onHoverChange?.(true)}
      onMouseLeave={() => onHoverChange?.(false)}
    >
      <div className="absolute flex gap-2 text-white/70 h-fit w-fit text-[.6vw] px-[.5vw] pt-[.3vw] py-[.1vw]">
        <p>X:{position.x.toFixed(2)}</p>
        <p>Y:{position.y.toFixed(2)}</p>
      </div>
      <canvas ref={canvasRef} className="w-full h-full" />
    </div>
  );
}
